// ─── Stack in JavaScript ─────────────────────────────────────────────────────
//
// JavaScript has no built-in Stack class — arrays serve as stacks perfectly.
// push/pop operate on the end (O(1) amortized), giving true LIFO behaviour.
// Never use shift/unshift for a stack: those are O(n) (front of array).

const stack = [];

// ── O(1) — Push (add to top) ─────────────────────────────────────────────
stack.push(10); // [10]
stack.push(20); // [10, 20]
stack.push(30); // [10, 20, 30]

// ── O(1) — Peek (read top without removing) ──────────────────────────────
const top = stack.at(-1);        // 30  (modern, preferred)
const top2 = stack[stack.length - 1]; // 30  (compatible with older envs)

// ── O(1) amortized — Pop (remove top) ────────────────────────────────────
const removed = stack.pop();     // 30, stack = [10, 20]

// ── O(1) — isEmpty ───────────────────────────────────────────────────────
const empty = stack.length === 0; // false

// ── O(n) — Search (scan from top) ────────────────────────────────────────
// Stacks do not support random access — you must scan from the top.
const idx = stack.lastIndexOf(20); // 1 (index, not position from top)

// ─────────────────────────────────────────────────────────────────────────
// Pattern 1 — Balanced parentheses                          O(n) time/space
// ─────────────────────────────────────────────────────────────────────────
function isBalanced(s) {
  const stack = [];
  const match = { ')': '(', ']': '[', '}': '{' };
  for (const ch of s) {
    if ('([{'.includes(ch)) stack.push(ch);
    else if ('])}'.includes(ch)) {
      if (stack.pop() !== match[ch]) return false;
    }
  }
  return stack.length === 0;
}
// isBalanced("({[]})") → true
// isBalanced("({[})") → false

// ─────────────────────────────────────────────────────────────────────────
// Pattern 2 — Monotonic stack (next greater element)        O(n) time/space
// ─────────────────────────────────────────────────────────────────────────
// For each element, find the next element to its right that is greater.
function nextGreater(nums) {
  const result = new Array(nums.length).fill(-1);
  const stack = []; // stores indices
  for (let i = 0; i < nums.length; i++) {
    while (stack.length && nums[stack.at(-1)] < nums[i]) {
      result[stack.pop()] = nums[i];
    }
    stack.push(i);
  }
  return result;
}
// nextGreater([2, 1, 2, 4, 3]) → [4, 2, 4, -1, -1]

// ─────────────────────────────────────────────────────────────────────────
// Pattern 3 — Evaluate RPN (Reverse Polish Notation)        O(n) time/space
// ─────────────────────────────────────────────────────────────────────────
function evalRPN(tokens) {
  const stack = [];
  const ops = { '+': (a, b) => a + b, '-': (a, b) => a - b,
                '*': (a, b) => a * b, '/': (a, b) => Math.trunc(a / b) };
  for (const t of tokens) {
    if (ops[t]) {
      const b = stack.pop(), a = stack.pop();
      stack.push(ops[t](a, b));
    } else {
      stack.push(Number(t));
    }
  }
  return stack[0];
}
// evalRPN(["2","1","+","3","*"]) → 9  ((2+1)*3)

// ─── Stack in Java ───────────────────────────────────────────────────────────
//
// Java offers two main options:
//   Deque<T> (ArrayDeque)  — preferred; faster than legacy Stack<T>.
//   Stack<T>               — extends Vector (synchronized, legacy); avoid for
//                            new code unless you specifically need thread safety.

import java.util.ArrayDeque;
import java.util.Deque;
import java.util.Stack;

public class StackOps {

    public static void main(String[] args) {

        // ── Deque as stack (preferred) ────────────────────────────────────
        Deque<Integer> stack = new ArrayDeque<>();

        // O(1) — Push
        stack.push(10); // [10]      (push = addFirst on Deque)
        stack.push(20); // [20, 10]
        stack.push(30); // [30, 20, 10]

        // O(1) — Peek (read top without removing)
        int top = stack.peek();    // 30  (returns null if empty)
        int top2 = stack.peekFirst(); // same as peek()

        // O(1) — Pop (remove top)
        int removed = stack.pop(); // 30, stack = [20, 10]

        // O(1) — isEmpty
        boolean empty = stack.isEmpty(); // false

        // ── Legacy Stack<T> (still valid, just slower) ────────────────────
        Stack<Integer> legacy = new Stack<>();
        legacy.push(10);
        legacy.push(20);
        int legacyTop = legacy.peek();    // 20
        int legacyPop = legacy.pop();     // 20
        int pos = legacy.search(10);      // 1-based position from top
    }

    // ─────────────────────────────────────────────────────────────────────
    // Pattern 1 — Balanced parentheses                      O(n) time/space
    // ─────────────────────────────────────────────────────────────────────
    static boolean isBalanced(String s) {
        Deque<Character> stack = new ArrayDeque<>();
        for (char ch : s.toCharArray()) {
            if (ch == '(' || ch == '[' || ch == '{') {
                stack.push(ch);
            } else if (ch == ')' || ch == ']' || ch == '}') {
                if (stack.isEmpty()) return false;
                char open = stack.pop();
                if ((ch == ')' && open != '(') ||
                    (ch == ']' && open != '[') ||
                    (ch == '}' && open != '{')) return false;
            }
        }
        return stack.isEmpty();
    }

    // ─────────────────────────────────────────────────────────────────────
    // Pattern 2 — Monotonic stack (next greater element)    O(n) time/space
    // ─────────────────────────────────────────────────────────────────────
    static int[] nextGreater(int[] nums) {
        int[] result = new int[nums.length];
        java.util.Arrays.fill(result, -1);
        Deque<Integer> stack = new ArrayDeque<>(); // stores indices
        for (int i = 0; i < nums.length; i++) {
            while (!stack.isEmpty() && nums[stack.peek()] < nums[i]) {
                result[stack.pop()] = nums[i];
            }
            stack.push(i);
        }
        return result;
    }

    // ─────────────────────────────────────────────────────────────────────
    // Pattern 3 — Min stack (getMin in O(1))                O(n) space
    // ─────────────────────────────────────────────────────────────────────
    static class MinStack {
        private final Deque<int[]> stack = new ArrayDeque<>(); // [value, minSoFar]

        public void push(int val) {
            int min = stack.isEmpty() ? val : Math.min(val, stack.peek()[1]);
            stack.push(new int[]{val, min});
        }
        public int pop()    { return stack.pop()[0]; }
        public int peek()   { return stack.peek()[0]; }
        public int getMin() { return stack.peek()[1]; } // O(1)
    }
}

// ─── Stack in C++ ────────────────────────────────────────────────────────────
//
// C++ STL provides std::stack<T> — a container adaptor defaulting to std::deque
// underneath. You can swap the backing store: std::stack<T, std::vector<T>>
// gives slightly better cache locality for push/pop-heavy workloads.

#include <iostream>
#include <stack>
#include <vector>
#include <string>

int main() {

    // ── std::stack (default deque backing) ───────────────────────────────
    std::stack<int> st;

    // O(1) — Push
    st.push(10);  // [10]
    st.push(20);  // [10, 20]
    st.push(30);  // [10, 20, 30]

    // O(1) — Peek (read top without removing)
    int top = st.top();  // 30

    // O(1) — Pop (removes top; does NOT return the value — call top() first)
    st.pop();            // stack = [10, 20]

    // O(1) — size / empty
    std::size_t sz = st.size();  // 2
    bool empty     = st.empty(); // false

    // ── Vector-backed stack (better cache locality) ───────────────────────
    std::stack<int, std::vector<int>> vec_stack;
    vec_stack.push(10);
    vec_stack.push(20);
    int v = vec_stack.top(); // 20
    vec_stack.pop();

    return 0;
}

// ─────────────────────────────────────────────────────────────────────────────
// Pattern 1 — Balanced parentheses                          O(n) time/space
// ─────────────────────────────────────────────────────────────────────────────
bool isBalanced(const std::string& s) {
    std::stack<char> st;
    for (char ch : s) {
        if (ch == '(' || ch == '[' || ch == '{') {
            st.push(ch);
        } else if (ch == ')' || ch == ']' || ch == '}') {
            if (st.empty()) return false;
            char open = st.top(); st.pop();
            if ((ch == ')' && open != '(') ||
                (ch == ']' && open != '[') ||
                (ch == '}' && open != '{')) return false;
        }
    }
    return st.empty();
}

// ─────────────────────────────────────────────────────────────────────────────
// Pattern 2 — Monotonic stack (next greater element)        O(n) time/space
// ─────────────────────────────────────────────────────────────────────────────
std::vector<int> nextGreater(const std::vector<int>& nums) {
    std::vector<int> result(nums.size(), -1);
    std::stack<int> st; // stores indices
    for (int i = 0; i < (int)nums.size(); i++) {
        while (!st.empty() && nums[st.top()] < nums[i]) {
            result[st.top()] = nums[i];
            st.pop();
        }
        st.push(i);
    }
    return result;
}

// ─────────────────────────────────────────────────────────────────────────────
// Pattern 3 — Min stack (getMin in O(1))                    O(n) space
// ─────────────────────────────────────────────────────────────────────────────
class MinStack {
    std::stack<std::pair<int,int>> st; // {value, minSoFar}
public:
    void push(int val) {
        int mn = st.empty() ? val : std::min(val, st.top().second);
        st.push({val, mn});
    }
    void pop()     { st.pop(); }
    int  top()     { return st.top().first; }
    int  getMin()  { return st.top().second; } // O(1)
};
